package org.ltzin.skin;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;


public final class SkinLibrary {

    private static final List<SkinPreset> PRESETS = new ArrayList<>();

    static {
        register("goku",     "§7Goku",     "", "");
        register("haddock", "§7Red Haddock", "", "");
        register("zerotwo", "§7Zero Two", "", "");
        register("alexcop", "§7Alex Cop", "", "");
        register("satoru", "§7Satoru Gojo", "", "");
        register("sukuna", "§7Sukuna Heian", "", "");
        register("yuji", "§7Yuji Itadori", "", "");
        register("reflexoo", "§7Reflexoo__", "", "");
        register("islostt", "§7D4RKK", "", "");
        register("udiego", "§7uDiego", "", "");
        register("brazzly", "§7Brazzlly", "", "");
        register("spop", "§7Spop", "", "");
        register("bronze", "§7Silcky Bronze", "", "");
        register("fuchsia", "§7Fuchsia", "", "");
        register("anteater", "§7Anteater", "", "");
        register("egirl", "§7E-girl", "", "");
        register("aqquagibon", "§7Aqua Gibbon", "", "");
        register("bluerooster", "§7Blue Rooster", "", "");
        register("harlequinchristimas", "§7Harlequin Christimas", "", "");
        register("cooper", "§7Copper Galliform", "", "");
        register("redtiger", "§7Red Tiger", "", "");
        register("falcon", "§7Gray Falcon", "", "");

    }

    private SkinLibrary() {}

    public static void register(String id, String displayName, String value, String signature) {
        PRESETS.add(new SkinPreset(id, displayName, value, signature));
    }

    public static List<SkinPreset> getAll() {
        return Collections.unmodifiableList(PRESETS);
    }

    public static SkinPreset getById(String id) {
        for (SkinPreset preset : PRESETS) {
            if (preset.getId().equalsIgnoreCase(id)) {
                return preset;
            }
        }
        return null;
    }

    public static int size() {
        return PRESETS.size();
    }
}